def.body:
{% if T == String %}
        read_string
      {% elsif T < Number %}
        buf = uninitialized T
        dtype = NativeType.for(T)
        ret = LibHDF5.H5Aread(@id, dtype, pointerof(buf).as(Void*))
        raise Error.new("Failed to read attribute") if ret < 0
        buf
      {% else %}
        {% raise("Unsupported attribute type: #{T}") %}
      {% end %}

{% if T == String %}
        write_string(value)
      {% elsif T < Number %}
        dtype = NativeType.for(T)
        ret = LibHDF5.H5Awrite(@id, dtype, pointerof(value).as(Void*))
        raise Error.new("Failed to write attribute") if ret < 0
      {% else %}
        {% raise("Unsupported attribute type: #{T}") %}
      {% end %}

if has_key?(name)
  LibHDF5.H5Adelete(@loc_id, name)
end
{% if T == String %}
        write_string_attr(name, value)
      {% elsif T < Number %}
        write_scalar_attr(name, value)
      {% else %}
        {% raise("Use attrs[name] = value for scalar types (Number, String). For arrays use set_array.") %}
      {% end %}

if has_key?(name)
  LibHDF5.H5Adelete(@loc_id, name)
end
{% if T == String %}
        write_string_array_attr(name, value)
      {% elsif T < Number %}
        write_array_attr(name, value)
      {% else %}
        {% raise("Unsupported array element type for attribute: #{T}") %}
      {% end %}

{% if T == String %}
        ds = build_string_dataset(path, data.size.to_u64)
        ds.write_strings(data)
        TypedDataset(String).new(ds)
      {% else %}
        dims = [data.size.to_u64]
        ds = build_numeric_dataset(path, T, dims)
        ds.write(data)
        TypedDataset(T).new(ds)
      {% end %}

dims = shape.map(&.to_u64).to_a
resolved_opts = options || (
  build_options(chunk, compression, compression_level, shuffle, fletcher32, max_shape)
)
{% if T == String %}
        ds = build_string_dataset(path, dims, resolved_opts)
        TypedDataset(String).new(ds)
      {% else %}
        ds = build_numeric_dataset(path, T, dims, resolved_opts)
        TypedDataset(T).new(ds)
      {% end %}

{% if T == Int8 %}
        LibHDF5.h5t_native_int8_g
      {% elsif T == UInt8 %}
        LibHDF5.h5t_native_uint8_g
      {% elsif T == Int16 %}
        LibHDF5.h5t_native_int16_g
      {% elsif T == UInt16 %}
        LibHDF5.h5t_native_uint16_g
      {% elsif T == Int32 %}
        LibHDF5.h5t_native_int32_g
      {% elsif T == UInt32 %}
        LibHDF5.h5t_native_uint32_g
      {% elsif T == Int64 %}
        LibHDF5.h5t_native_int64_g
      {% elsif T == UInt64 %}
        LibHDF5.h5t_native_uint64_g
      {% elsif T == Float32 %}
        LibHDF5.h5t_native_float_g
      {% elsif T == Float64 %}
        LibHDF5.h5t_native_double_g
      {% else %}
        {% raise("Unsupported HDF5 type: #{T}") %}
      {% end %}

{% if T == String %}
        raise Error.new("Partial string I/O not supported")
      {% else %}
        @dataset.read(T, selection)
      {% end %}

{% if T == String %}
        raise Error.new("Partial string I/O not supported")
      {% else %}
        @dataset.write(data, selection)
      {% end %}

{% if T == String %}
        raise Error.new("Slice write not supported for String datasets")
      {% else %}
        @dataset.write(data)
      {% end %}
